request.query:
BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?subPkg ?name WHERE {
  ?parent vocab:NamedElement_name "Conceptual Design" .
  ?parent vocab:Element_ownedElement ?subPkg .
  ?subPkg rdf:type vocab:package .
  OPTIONAL { ?subPkg vocab:NamedElement_name ?name }
}
LIMIT 50
